#!/usr/bin/env python3
"""Assemble the review-artifact index.html for task-2026-07-13-005.

Starts from the maintained spatial-3d template, replaces the three data blocks
(REVIEW_MANIFEST, REVIEW_GEOMETRY sentinel, REVIEW_EVIDENCE literal), and applies
three bounded, data-driven edits so BOTH decisive ratios render (this protocol has
two ratios + 8 landmarks across two bones; the stock template is single-metric):
  E1  all decisive entries' measurement lines draw in 3D (tibial lines included)
  E2  the evidence banner shows both ratios, flagged-first
  E3  the Values tab shows all nine rows + honesty flags (null-safe)
No science is done here — this packages vetted outputs.
"""
import json, hashlib, os

TASK = "/home/jimyao/gitrepos/labrat/tasks/task-2026-07-13-005"
TPL = "/home/jimyao/.claude-science/orgs/1ba877d1-4bed-4233-b543-1e5977b5b263/skills/review-artifact-builder/assets/templates/spatial-3d/index.html"
OUT = os.path.join(TASK, "artifacts/review-site/index.html")

def sha(p):
    return hashlib.sha256(open(p, "rb").read()).hexdigest()

geo_path = os.path.join(TASK, "artifacts/segmentation/geometry.json")
res_path = os.path.join(TASK, "artifacts/measurements/results.json")
GEO_HASH = sha(geo_path)
RES_HASH = sha(res_path)

pos = json.load(open(os.path.join(TASK, "artifacts/landmarks/positions.json")))
# mesh frame [x,y,z]mm = [vx*s, vy*s, vz*s] = physical reversed (physical is [vz*s,vy*s,vx*s])
mesh_pos = {l["id"]: [round(v, 4) for v in l["physical"][::-1]] for l in pos["landmarks"]}

# ---- REVIEW_MANIFEST ---------------------------------------------------------
manifest = {
    "sample_id": "task-2026-07-13-005",
    "phase": "review-artifact",
    "review_layout": "spatial-multipane",
    "required_views": ["scene3d"],
    "landmarks_available": True,
    "produced_from": {
        "measurement": f"measurements/results.json@{RES_HASH}",
        "geometry": f"segmentation/geometry.json@{GEO_HASH}",
    },
    "verdict_schema": "review-verdict/1",
    "data_globals": ["REVIEW_MANIFEST", "REVIEW_EVIDENCE", "REVIEW_GEOMETRY"],
    "data_sources": {
        "REVIEW_GEOMETRY": {"artifact": "segmentation/geometry.json", "transform": "identity"},
    },
}

# ---- REVIEW_EVIDENCE ---------------------------------------------------------
FEM_KL = ("Femoral groove-top 'A' is subjective (paper places by eye, ICC 0.667-0.85) "
          "and controls the precise ROC/severity bin. OA-vs-normal is ROBUST: the "
          "sensitivity band [1.302, 1.515] lies entirely above the OA cutoff 1.30 (and "
          "above normal<1.24, 4wk ROC 1.245, AROA 1.282); it straddles ONLY the 8wk PTOA "
          "ROC cutoff 1.312. Sesamoids/osteophytes are separate labels and do not inflate "
          "the femur-label condyle width.")
TIB_KL = ("Growth-plate boundary is the weakest landmark (+-10 vox; thin cartilage + "
          "trabecular noise). The OA call (H/W<0.282) is ROBUST: band [0.182, 0.258] lies "
          "entirely below the cutoff and clear of the 0.28-0.30 gray zone. The height "
          "VALUE is uncertain. Lateral tibial width may include onset of metaphyseal flare. "
          "Compartment heights comparable (medial ~0.69 / lateral ~0.75 mm) -> growth plate "
          "not misplaced on one side.")

evidence = {
    "decisive": [
        {
            "id": "distal_femoral_ratio",
            "label": "Distal femoral W/L (osteophyte index)",
            "value": 1.3182, "unit": "ratio",
            "cutoff": {"normal_below": 1.24, "oa_above": 1.30},
            "state": "concern",
            "requires_human_review": True,
            "known_limits": FEM_KL,
            "sub_measurements": [
                {"id": "distal_femoral_length", "label": "Distal femoral length", "value": 1.7211, "unit": "mm"},
                {"id": "distal_femoral_width", "label": "Distal femoral width", "value": 2.2688, "unit": "mm"},
            ],
            "measurement_lines": [
                {"id": "femoral_length", "from": "intercondylar_groove_midpoint", "to": "intercondylar_notch", "value_mm": 1.7211},
                {"id": "femoral_width", "from": "lateral_condylar_edge", "to": "medial_condylar_edge", "value_mm": 2.2688},
            ],
        },
        {
            "id": "tibial_iioc_ratio",
            "label": "Tibial IIOC height/width",
            "value": 0.2184, "unit": "ratio",
            "cutoff": {"oa_below": 0.282, "gray_zone": [0.28, 0.30]},
            "state": "concern",
            "requires_human_review": True,
            "known_limits": TIB_KL,
            "sub_measurements": [
                {"id": "tibial_iioc_height", "label": "Tibial IIOC height", "value": 0.6014, "unit": "mm"},
                {"id": "tibial_width", "label": "Tibial width", "value": 2.7535, "unit": "mm"},
            ],
            "measurement_lines": [
                {"id": "iioc_height", "from": "articular_surface_proximal", "to": "growth_plate_proximal", "value_mm": 0.6014},
                {"id": "tibial_width", "from": "lateral_tibial_condyle_edge", "to": "medial_tibial_condyle_edge", "value_mm": 2.7535},
            ],
        },
    ],
    "interpretation": {
        "stage": "established OA",
        "confidence": "low",
        "basis": (
            "Both indices cross their OA cutoffs in a concordant direction: the osteophyte "
            "index W/L is elevated at 1.32 (vs WT-normal ~1.19; near the 4wk-MMS mean ~1.33) "
            "and the subchondral index IIOC H/W is depressed at 0.22 (vs normal ~0.304). "
            "Magnitudes disagree on severity - W/L reads roughly 4-week-established while H/W "
            "sits below even the 8wk mean (~0.24), suggesting more advanced subchondral "
            "collapse - so the direction is trustworthy but the timepoint bin is not. "
            "Confidence is low: the femoral groove-top is subjective and the growth-plate is "
            "the weakest landmark, the enlargement axis (patella + peri-meniscal volumes) is "
            "unavailable (not segmented), and this is a single specimen."
        ),
    },
    "landmarks": [
        {"name": "intercondylar_groove_midpoint", "position": mesh_pos["intercondylar_groove_midpoint"],
         "confidence": "medium", "color": [255, 190, 70],
         "operational_rule": "Proximal-most slice of the sustained anterior-midline concavity, proximal to the condylar bulge - NOT where the condyles merge (the half-length trap).",
         "flags": ["requires_human_review: subjective groove-top; controls precise W/L ROC bin"],
         "contributes_to": ["distal_femoral_ratio"], "measurement_lines": ["femoral_length"]},
        {"name": "growth_plate_proximal", "position": mesh_pos["growth_plate_proximal"],
         "confidence": "medium", "color": [230, 140, 220],
         "operational_rule": "Epiphyseal line - the drop in bone-fill ratio along the tibial long axis; the growth plate, not the marrow below it.",
         "flags": ["requires_human_review: weakest landmark +-10 vox; H/W OA call robust, height value uncertain"],
         "contributes_to": ["tibial_iioc_ratio"], "measurement_lines": ["iioc_height"]},
        {"name": "articular_surface_proximal", "position": mesh_pos["articular_surface_proximal"],
         "confidence": "medium", "color": [150, 220, 120],
         "operational_rule": "Proximal-most articular/subchondral bone of the max-height (lateral) compartment, along the reoriented long axis.",
         "flags": ["requires_human_review"],
         "contributes_to": ["tibial_iioc_ratio"], "measurement_lines": ["iioc_height"]},
        {"name": "lateral_tibial_condyle_edge", "position": mesh_pos["lateral_tibial_condyle_edge"],
         "confidence": "medium", "color": [120, 200, 230],
         "operational_rule": "Lateral tibial plateau border at growth-plate level, on the max-height frontal ortho slice (may include onset of metaphyseal flare).",
         "flags": ["requires_human_review"],
         "contributes_to": ["tibial_iioc_ratio"], "measurement_lines": ["tibial_width"]},
        {"name": "medial_tibial_condyle_edge", "position": mesh_pos["medial_tibial_condyle_edge"],
         "confidence": "medium", "color": [120, 200, 230],
         "operational_rule": "Medial tibial plateau border at growth-plate level, on the max-height frontal ortho slice.",
         "flags": ["requires_human_review"],
         "contributes_to": ["tibial_iioc_ratio"], "measurement_lines": ["tibial_width"]},
        {"name": "intercondylar_notch", "position": mesh_pos["intercondylar_notch"],
         "confidence": "high", "color": [255, 120, 120],
         "operational_rule": "Distal-most midline bone point (roof of the intercondylar fossa). Not eroded here - no fallback needed.",
         "flags": [],
         "contributes_to": ["distal_femoral_ratio"], "measurement_lines": ["femoral_length"]},
        {"name": "lateral_condylar_edge", "position": mesh_pos["lateral_condylar_edge"],
         "confidence": "high", "color": [90, 170, 235],
         "operational_rule": "Mediolateral-extreme (lateral) bone point in the distal condylar slab, front view. Main condyle mass, sesamoid-free.",
         "flags": [],
         "contributes_to": ["distal_femoral_ratio"], "measurement_lines": ["femoral_width"]},
        {"name": "medial_condylar_edge", "position": mesh_pos["medial_condylar_edge"],
         "confidence": "high", "color": [90, 170, 235],
         "operational_rule": "Mediolateral-extreme (medial) bone point in the distal condylar slab, front view. Main condyle mass, sesamoid-free.",
         "flags": [],
         "contributes_to": ["distal_femoral_ratio"], "measurement_lines": ["femoral_width"]},
    ],
    "structural": {
        "segmentation_cc": {"femur": 1, "tibia": 1},
        "compartment_symmetry": {"medial_height": 0.69, "lateral_height": 0.75, "delta": 0.06, "status": "pass"},
    },
    # Drives the Values tab (E3). Exact 9-row order from the protocol resource.
    "values_rows": [
        {"label": "Distal femoral length", "value": 1.7211, "unit": "mm", "flag": "confirmed"},
        {"label": "Distal femoral width", "value": 2.2688, "unit": "mm", "flag": "confirmed"},
        {"label": "Distal femoral W/L (osteophyte index)", "value": 1.3182, "unit": "ratio", "flag": "low-margin (+0.02 over OA cutoff 1.30; OA-vs-normal robust)"},
        {"label": "Tibial width", "value": 2.7535, "unit": "mm", "flag": "confirmed (lateral edge may include flare onset)"},
        {"label": "Tibial IIOC height", "value": 0.6014, "unit": "mm", "flag": "review-needed (growth-plate +-10 vox)"},
        {"label": "Tibial IIOC height/width", "value": 0.2184, "unit": "ratio", "flag": "confirmed (OA call robust, band < 0.282)"},
        {"label": "Patella volume", "value": None, "unit": "mm3", "flag": "review-needed (not segmented; escalated)"},
        {"label": "Medial peri-meniscal volume", "value": None, "unit": "mm3", "flag": "review-needed (not segmented; intrinsically variable)"},
        {"label": "Lateral peri-meniscal volume", "value": None, "unit": "mm3", "flag": "review-needed (not segmented; the paper's early change)"},
    ],
}

# ---- assemble ----------------------------------------------------------------
lines = open(TPL, encoding="utf-8").read().split("\n")
# data blocks: manifest 1382-1396, geometry 1397-1399, evidence 1400-1446 (1-based inclusive)
head = lines[:1381]           # lines 1..1381
tail = lines[1446:]           # line 1447 onward
new_blocks = [
    "<script>",
    "window.REVIEW_MANIFEST = " + json.dumps(manifest, indent=2) + ";",
    "</script>",
    "<script>",
    'window.REVIEW_GEOMETRY = "__REVIEW_INJECT:REVIEW_GEOMETRY__";',
    "</script>",
    "<script>",
    "window.REVIEW_EVIDENCE = " + json.dumps(evidence, indent=2) + ";",
    "</script>",
]
html = "\n".join(head + new_blocks + tail)

# ---- E1: all decisive measurement lines draw --------------------------------
e1_old = "var measurementLines = HAS_EVIDENCE && Array.isArray(decisive.measurement_lines) ? decisive.measurement_lines : [];"
e1_new = ("var measurementLines = HAS_EVIDENCE ? EV.decisive.reduce(function (acc, d) { "
          "return acc.concat(Array.isArray(d.measurement_lines) ? d.measurement_lines : []); }, []) : [];")
assert html.count(e1_old) == 1, "E1 anchor not unique"
html = html.replace(e1_old, e1_new)

# ---- E2: banner shows both decisive ratios (replace renderBanner body) -------
e2_old = """  function renderBanner() {
    var banner = document.getElementById("evidence-banner");
    banner.textContent = "";
    var state = STATE_COLOR[decisive.state] || "#4b5563";

    var metric = document.createElement("div");
    metric.className = "ev-metric";
    metric.style.setProperty("--state", state);
    var label = document.createElement("span");
    label.className = "ev-label";
    label.textContent = decisive.label;
    var val = document.createElement("span");
    val.className = "ev-value";
    val.textContent = decisive.value.toFixed(2);
    var unit = document.createElement("span");
    unit.className = "ev-unit";
    unit.textContent = " " + decisive.unit;
    val.appendChild(unit);
    var cut = document.createElement("span");
    cut.className = "ev-cut";
    var oa = decisive.cutoff.oa_above;
    var delta = decisive.value - oa;
    var side = delta >= 0 ? "above" : "below";
    cut.appendChild(document.createTextNode("OA cutoff ≥ " + oa.toFixed(2) + " · "));
    var b = document.createElement("b");
    b.textContent = (delta >= 0 ? "+" : "−") + Math.abs(delta).toFixed(2) + " " + side + " cutoff";
    cut.appendChild(b);
    metric.appendChild(label);
    metric.appendChild(val);
    metric.appendChild(cut);
    banner.appendChild(metric);

    var status = document.createElement("div");
    status.className = "ev-status";
    status.style.setProperty("--state", state);
    var icon = document.createElement("span");
    icon.className = "ev-status-icon";
    icon.setAttribute("role", "img");
    var needsReview = decisive.requires_human_review;
    icon.setAttribute("aria-label", needsReview ? "Review required" : "Pass");
    icon.textContent = needsReview ? "⚠" : "✓";
    var stext = document.createElement("span");
    stext.className = "ev-status-text";
    var main = document.createElement("span");
    main.className = "ev-status-main";
    main.textContent = needsReview ? "Review required" : "Within tolerance";
    var sub = document.createElement("span");
    sub.className = "ev-status-sub";
    var conf = (EV.interpretation && EV.interpretation.confidence) || "";
    sub.textContent = conf ? humanize(conf) + " confidence" : "";
    stext.appendChild(main);
    stext.appendChild(sub);
    status.appendChild(icon);
    status.appendChild(stext);
    banner.appendChild(status);
  }"""
e2_new = """  function renderBanner() {
    var banner = document.getElementById("evidence-banner");
    banner.textContent = "";
    var anyReview = false;
    (EV.decisive || []).forEach(function (d) {
      if (d.requires_human_review) anyReview = true;
      var state = STATE_COLOR[d.state] || "#4b5563";
      var metric = document.createElement("div");
      metric.className = "ev-metric";
      metric.style.setProperty("--state", state);
      var label = document.createElement("span");
      label.className = "ev-label";
      label.textContent = d.label;
      var val = document.createElement("span");
      val.className = "ev-value";
      val.textContent = d.value.toFixed(2);
      var unit = document.createElement("span");
      unit.className = "ev-unit";
      unit.textContent = " " + d.unit;
      val.appendChild(unit);
      var cut = document.createElement("span");
      cut.className = "ev-cut";
      var hasHi = d.cutoff && typeof d.cutoff.oa_above === "number";
      var thr = hasHi ? d.cutoff.oa_above : (d.cutoff ? d.cutoff.oa_below : 0);
      var delta = d.value - thr;
      var oaSide = hasHi ? (delta >= 0) : (delta <= 0);
      cut.appendChild(document.createTextNode("OA cutoff " + (hasHi ? "≥ " : "≤ ") + thr.toFixed(2) + " · "));
      var b = document.createElement("b");
      b.textContent = (delta >= 0 ? "+" : "−") + Math.abs(delta).toFixed(2) + (oaSide ? " (OA side)" : " (normal side)");
      cut.appendChild(b);
      metric.appendChild(label);
      metric.appendChild(val);
      metric.appendChild(cut);
      if (d.requires_human_review) {
        var rf = document.createElement("span");
        rf.className = "ev-cut";
        rf.textContent = " ⚠ review";
        metric.appendChild(rf);
      }
      banner.appendChild(metric);
    });

    var status = document.createElement("div");
    status.className = "ev-status";
    var st0 = (EV.decisive && EV.decisive[0]) ? (STATE_COLOR[EV.decisive[0].state] || "#4b5563") : "#4b5563";
    status.style.setProperty("--state", st0);
    var icon = document.createElement("span");
    icon.className = "ev-status-icon";
    icon.setAttribute("role", "img");
    icon.setAttribute("aria-label", anyReview ? "Review required" : "Pass");
    icon.textContent = anyReview ? "⚠" : "✓";
    var stext = document.createElement("span");
    stext.className = "ev-status-text";
    var main = document.createElement("span");
    main.className = "ev-status-main";
    main.textContent = anyReview ? "Review required" : "Within tolerance";
    var sub = document.createElement("span");
    sub.className = "ev-status-sub";
    var conf = (EV.interpretation && EV.interpretation.confidence) || "";
    sub.textContent = conf ? humanize(conf) + " confidence" : "";
    stext.appendChild(main);
    stext.appendChild(sub);
    status.appendChild(icon);
    status.appendChild(stext);
    banner.appendChild(status);
  }"""
assert html.count(e2_old) == 1, "E2 anchor not unique"
html = html.replace(e2_old, e2_new)

# ---- E3: Values tab -> all nine rows + honesty flag (null-safe) --------------
e3_old = """    var vbody = document.getElementById("values-body");
    (decisive.sub_measurements || []).concat([
      { id: decisive.id, label: decisive.label, value: decisive.value, unit: decisive.unit },
    ]).forEach(function (row) {
      var tr = document.createElement("tr");
      var td1 = document.createElement("td"); td1.textContent = row.label;
      var td2 = document.createElement("td"); td2.className = "num"; td2.textContent = row.value.toFixed(2) + " " + row.unit;
